#include<bits/stdc++.h>
using namespace std;
long long a[1000010],b[1000010];
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long min1;
    }a[3000010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].min1=b[l];
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long v)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].min1+=v;
            return;
        }
        update(a[x].lson,p,v);
        update(a[x].rson,p,v);
        pushup(x);
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1e9;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i]-a[i-1];
    }
    t.init(1,n);
    while(m--)
    {
        long long op,l,r;
        scanf("%lld%lld%lld",&op,&l,&r);
        if(r==n+1)
        {
            r=n;
        }
        if(op==1)
        {
            long long x;
            scanf("%lld",&x);
            t.update(1,l,x);
            t.update(1,r+1,-x);
        }
        else
        {
            if(l==r)
            {
                printf("Yes\n");
                continue;
            }
            if(t.getmin(1,l+1,r)>=0)
            {
                printf("Yes\n");
            }
            else
            {
                printf("No\n");
            }
        }
    }
    return 0;
}
